class Solution {
public:
    int maximumXOR(vector<int>& nums) {
        int max_val = 0;
        for (int num : nums) {
            max_val = max(max_val, num);
        }
        int max_bits = 0;
        while ((1 << max_bits) <= max_val) {
            max_bits++;
        }
        vector<int> trie(1, 0);
        for (int num : nums) {
            int node = 0;
            for (int i = max_bits - 1; i >= 0; i--) {
                int bit = (num >> i) & 1;
                if (trie[node] == 0) {
                    trie[node] = bit + 1;
                }
                node = trie[node] * 2 + bit;
            }
        }
        int max_xor = 0;
        for (int i = 0; i < (1 << max_bits); i++) {
            int node = 0;
            int xor = 0;
            for (int j = max_bits - 1; j >= 0; j--) {
                int bit = (i >> j) & 1;
                if (trie[node] == 0) {
                    break;
                }
                xor |= (bit ^ trie[node]);
                node = trie[node] * 2 + bit;
            }
            if (node != 0) {
                max_xor = max(max_xor, xor);
            }
        }
        return max_xor;
    }
};
